const maybeEnvKey = (typeof process !== "undefined" && process && process.env && typeof process.env.STRIPE_SECRET_KEY === "string") ? process.env.STRIPE_SECRET_KEY : "";
const apiKey = String(args.api_key || maybeEnvKey || "").trim();
if (!apiKey) return "Missing Stripe API key. Provide args.api_key (preferred restricted read-only key).";

const parseDateToUnix = (value, endOfDay = false) => {
  const raw = String(value || "").trim();
  if (!raw) throw new Error("Date is required (YYYY-MM-DD or ISO string).");
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) {
    const ts = endOfDay ? Date.parse(raw + "T23:59:59.999Z") : Date.parse(raw + "T00:00:00.000Z");
    if (Number.isNaN(ts)) throw new Error("Invalid date: " + raw);
    return Math.floor(ts / 1000);
  }
  const ts = Date.parse(raw);
  if (Number.isNaN(ts)) throw new Error("Invalid date: " + raw);
  return Math.floor(ts / 1000);
};

const centsToDollars = (cents) => (Number(cents || 0) / 100).toFixed(2);

const fetchAllCharges = async (startUnix, endUnix, maxRows = 10000) => {
  const out = [];
  let cursor = "";
  let hasMore = true;

  while (hasMore && out.length < maxRows) {
    const remaining = Math.max(1, Math.min(100, maxRows - out.length));
    const qp = new URLSearchParams();
    qp.set("created[gte]", String(startUnix));
    qp.set("created[lte]", String(endUnix));
    qp.set("limit", String(remaining));
    qp.append("expand[]", "data.balance_transaction");
    if (cursor) qp.set("starting_after", cursor);

    const res = await fetch("https://api.stripe.com/v1/charges?" + qp.toString(), {
      method: "GET",
      headers: {
        "authorization": "Bearer " + apiKey,
      },
    });

    if (!res.ok) {
      let details = "";
      try {
        details = await res.text();
      } catch {
        details = "";
      }
      const shortDetails = details ? details.slice(0, 500) : "";
      throw new Error("Stripe API error " + res.status + (shortDetails ? (": " + shortDetails) : ""));
    }

    const payload = await res.json();
    const rows = Array.isArray(payload && payload.data) ? payload.data : [];
    for (const row of rows) out.push(row);

    hasMore = Boolean(payload && payload.has_more) && rows.length > 0;
    cursor = rows.length > 0 ? String(rows[rows.length - 1].id || "") : "";
    if (!cursor) hasMore = false;
  }

  return out;
};

const normalizeCharge = (charge) => {
  const amount = Number(charge && charge.amount || 0);
  const refunded = Number(charge && charge.amount_refunded || 0);
  const bt = charge && charge.balance_transaction && typeof charge.balance_transaction === "object" ? charge.balance_transaction : null;
  const fee = Number(bt && bt.fee || 0);
  return {
    id: String(charge && charge.id || ""),
    created: Number(charge && charge.created || 0),
    created_iso: new Date(Number(charge && charge.created || 0) * 1000).toISOString(),
    amount,
    amount_refunded: refunded,
    fee,
    net: amount - refunded - fee,
    currency: String(charge && charge.currency || "").toLowerCase(),
    status: String(charge && charge.status || ""),
    paid: Boolean(charge && charge.paid),
    refunded: Boolean(charge && charge.refunded),
    customer: charge && charge.customer ? String(charge.customer) : "",
    receipt_email: charge && charge.receipt_email ? String(charge.receipt_email) : "",
    description: charge && charge.description ? String(charge.description) : "",
  };
};
const startDate = String(args.start_date || "").trim();
const endDate = String(args.end_date || "").trim();
if (!startDate || !endDate) return "start_date and end_date are required.";

let startUnix = 0;
let endUnix = 0;
try {
  startUnix = parseDateToUnix(startDate, false);
  endUnix = parseDateToUnix(endDate, true);
} catch (e) {
  return "Invalid date input: " + (e && e.message ? e.message : String(e));
}

if (endUnix < startUnix) return "end_date must be on or after start_date.";

const maxRows = Math.max(1, Math.min(10000, Number(args.limit || 100)));

try {
  const charges = await fetchAllCharges(startUnix, endUnix, maxRows);
  const normalized = charges.map(normalizeCharge);
  const currencies = Array.from(new Set(normalized.map((c) => c.currency).filter(Boolean)));
  return JSON.stringify({
    start_date: startDate,
    end_date: endDate,
    start_unix: startUnix,
    end_unix: endUnix,
    count_charges: normalized.length,
    currencies,
    charges: normalized,
  }, null, 2);
} catch (e) {
  return "Failed to list charges: " + (e && e.message ? e.message : String(e));
}

