const year = Number(args.year);
if (!Number.isInteger(year) || year < 2000 || year > 2100) return "year must be an integer between 2000 and 2100.";

const start = Date.UTC(year, 0, 1, 0, 0, 0, 0);
const end = Date.UTC(year, 1, 0, 23, 59, 59, 999);
const startUnix = Math.floor(start / 1000);
const endUnix = Math.floor(end / 1000);

try {
  const charges = await fetchAllCharges(startUnix, endUnix, 10000);
  const normalized = charges.map(normalizeCharge);

  let gross = 0;
  let refunds = 0;
  let fees = 0;
  let count = 0;
  const currencyTotals = {};

  for (const c of normalized) {
    if (!c.paid || c.status !== "succeeded") continue;
    count += 1;
    gross += c.amount;
    refunds += c.amount_refunded;
    fees += c.fee;

    const curr = c.currency || "unknown";
    if (!currencyTotals[curr]) {
      currencyTotals[curr] = { gross: 0, refunds: 0, fees: 0, net: 0, count_charges: 0 };
    }
    currencyTotals[curr].gross += c.amount;
    currencyTotals[curr].refunds += c.amount_refunded;
    currencyTotals[curr].fees += c.fee;
    currencyTotals[curr].net += (c.amount - c.amount_refunded - c.fee);
    currencyTotals[curr].count_charges += 1;
  }

  const net = gross - refunds - fees;
  const summary = {
    month: "January",
    year,
    period_start_utc: new Date(start).toISOString(),
    period_end_utc: new Date(end).toISOString(),
    count_charges: count,
    gross_cents: gross,
    refunds_cents: refunds,
    fees_cents: fees,
    net_cents: net,
    gross_usd: centsToDollars(gross),
    refunds_usd: centsToDollars(refunds),
    fees_usd: centsToDollars(fees),
    net_usd: centsToDollars(net),
    currency_breakdown: currencyTotals,
    note: Object.keys(currencyTotals).length > 1 ? "Multiple currencies detected; USD fields are raw cents/100 without FX conversion." : undefined,
  };

  return JSON.stringify(summary, null, 2);
} catch (e) {
  return "Failed to generate January summary: " + (e && e.message ? e.message : String(e));
}

