const escapeCsv = (value) => {
  const s = String(value == null ? "" : value);
  if (/[",\n]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
};

try {
  const charges = await fetchAllCharges(startUnix, endUnix, 10000);
  const normalized = charges.map(normalizeCharge);
  const header = [
    "id",
    "created",
    "amount",
    "amount_refunded",
    "fee",
    "net",
    "currency",
    "status",
    "paid",
    "refunded",
    "customer",
    "receipt_email",
    "description",
  ];

  const lines = [header.join(",")];
  for (const c of normalized) {
    lines.push([
      c.id,
      c.created_iso,
      c.amount,
      c.amount_refunded,
      c.fee,
      c.net,
      c.currency,
      c.status,
      c.paid,
      c.refunded,
      c.customer,
      c.receipt_email,
      c.description,
    ].map(escapeCsv).join(","));
  }

  const csv = lines.join("\n");
  const exportId = "charges_" + startDate + "_" + endDate + "_" + Date.now();
  await moduleStore.upsert("exports", exportId, {
    exportId,
    start_date: startDate,
    end_date: endDate,
    count_charges: normalized.length,
    csv,
    createdAt: Date.now(),
  }, ["stripe", "csv", "charges"]);

  if (csv.length > 120000) {
    return JSON.stringify({
      message: "CSV is large; saved in module store.",
      export_id: exportId,
      count_charges: normalized.length,
      preview: lines.slice(0, 20).join("\n"),
    }, null, 2);
  }

  return csv;
} catch (e) {
  return "Failed to export CSV: " + (e && e.message ? e.message : String(e));
}
